mapper.select:
SELECT * FROM lkt_bbs_post_action
WHERE
    user_id = #{user_id} AND post_id = #{post_id} AND recycle = 0 AND action_type = #{type}

SELECT count(1) FROM lkt_bbs_post_action a WHERE a.recycle = 0 AND a.action_type = 4
AND EXISTS ( SELECT 1 FROM lkt_bbs_post_action b WHERE b.user_id = a.be_user_id AND b.be_user_id = a.user_id AND b.action_type = 4 AND b.recycle = 0 ) AND a.user_id = #{user_id}
AND a.user_id = #{user_id}
AND a.be_user_id = #{user_id}
ORDER BY a.create_time desc

SELECT a.user_id AS user1, a.be_user_id AS user2, a.forum_id FROM lkt_bbs_post_action a WHERE a.recycle = 0 AND a.action_type = 4
AND EXISTS ( SELECT 1 FROM lkt_bbs_post_action b WHERE b.user_id = a.be_user_id AND b.be_user_id = a.user_id AND b.action_type = 4 AND b.recycle = 0 ) AND a.user_id = #{user_id}
AND a.user_id = #{user_id}
AND a.be_user_id = #{user_id}
ORDER BY a.create_time desc
limit #{pageNo},#{pageSize}
